{%?($DOCROOT/@fil-group!='') {%, WRK02_VALS as V%} {% %} %}
{%?($SOURCE/@mode='OWNER_CHILD') 
{% 
,wrk05_organigramas as ORG_O
,wrk05_organigramas as ORG_P
,wrk05_estructura as EST
,wrk05_estructura as EST_CC
,wrk05_estr_estr as EST_C
