%} join
W.oi_wf inner I.oi_wf
{%?($DOCROOT/@fil-group!='') {%, V.oi_instance inner I.oi_instance %} {% %} %}
{%?($SOURCE/@mode='OWNER_CHILD') 
{% 
,I.oi_wf inner W.oi_wf
,I.c_estructura inner EST_C.c_estructura
,W.oi_organigrama inner ORG_O.oi_organigrama
,PER.oi_estructura inner EST.oi_estructura
,EST_C.oi_estructura inner EST.oi_estructura
,EST_C.c_estructura inner EST_CC.c_estructura
,ORG_P.oi_organigrama inner EST_CC.oi_organigrama
,ORG_P.oi_organigrama inner EST.oi_organigrama
,ORG_P.c_organigrama inner ORG_O.c_organigrama
,ORG_P.e_version inner ORG_O.e_version_pub
%} 
{% %} 
%}
where         
I.l_debug = {$DOCROOT/@DEBUG}
{%?($SOURCE/@mode='OWNER_CHILD') 
{% 
and ORG_O.l_automatica=0
and EST_C.e_deep>0           
and PER.oi_entidad={$DOCROOT/@ETTY}
%} 
{% %} 
%}
{%?($SOURCE/@mode='OWNER') {% and I.d_owner={$DOCROOT/@ETTY} %} {% %} %}
{%?($SOURCE/@wf!='') {% and W.c_wf={$SOURCE/@wf} %} {% %} %}
{%?($DOCROOT/@fil-estado!='') {%=' and '+translate(translate(translate($DOCROOT/@fil-estado,'[I]','I'),'[W]','W'),'[V]','V') %}  {% %} %}
{%?($DOCROOT/@fil-group!='') {% and V.c_var_group={$DOCROOT/@fil-group} %} {% %} %}
{%?($DOCROOT/@fil-cond1!='' and $DOCROOT/@fil-value1!='') {%=' and '+translate(translate(translate($DOCROOT/@fil-cond1,'[I]','I'),'[W]','W'),'[V]','V') %}  {% %} %}
{%?($DOCROOT/@fil-cond2!='' and $DOCROOT/@fil-value2!='') {%=' and '+translate(translate(translate($DOCROOT/@fil-cond2,'[I]','I'),'[W]','W'),'[V]','V') %} {% %} %}
')/ROWS/ROW

				for $r in SQL('
select
count(T.oi_thread) as cnt

from
wrk01_wf as W, wrk02_instances as I, wrk02_threads as T, wrk02_users as U
{%?($DOCROOT/@fil-group!='') {%, WRK02_VALS as V %} {% %} %}

join
I.oi_wf inner W.oi_wf, I.oi_instance inner T.oi_instance, T.oi_thread inner U.oi_thread
{%?($DOCROOT/@fil-group!='') {%, V.oi_instance inner I.oi_instance %} {% %} %}

where                                             
I.l_debug = {$DOCROOT/@DEBUG} and U.l_resolve=1 and U.oi_etty = {$DOCROOT/@ETTY} and
I.c_estado_ej=\'R\' and T.c_estado=\'WP\' 

{%?($DOCROOT/@fil-group!='') {% and V.c_var_group={$DOCROOT/@fil-group} %} {% %} %}
{%?($DOCROOT/@fil-cond1 !='' and $DOCROOT/@fil-value1!='') {%=' and '+translate(translate(translate($DOCROOT/@fil-cond1,'[I]','I'),'[W]','W'),'[V]','V') %} {% %} %}
{%?($DOCROOT/@fil-cond2 !='' and $DOCROOT/@fil-value2!='') {%=' and '+translate(translate(translate($DOCROOT/@fil-cond2,'[I]','I'),'[W]','W'),'[V]','V') %} {% %} %}
{%?($DOCROOT/@fil-estado!='') {%=' and '+translate(translate(translate(translate($DOCROOT/@fil-estado,'[I]','I'),'[W]','W'),'[V]','V'),'[T]','T') %}  {% %} %}
{%?($SOURCE/@wf!='') {% and W.c_wf={$SOURCE/@wf} %} {% %} %}

')/ROWS/ROW

				for $r in SQL('
fromrow {%=$SOURCE/@start %}
maxsize {%=$SOURCE/@size %}
select
T.oi_thread, I.oi_instance, T.f_vencimiento

from
wrk01_wf as W, wrk02_instances as I, wrk02_threads as T, wrk02_users as U
{%?($DOCROOT/@fil-group!='') {%, WRK02_VALS as V %} {% %} %}

join
I.oi_wf inner W.oi_wf, I.oi_instance inner T.oi_instance, T.oi_thread inner U.oi_thread
{%?($DOCROOT/@fil-group!='') {%, V.oi_instance inner I.oi_instance %} {% %} %}

where                                             
I.l_debug = {$DOCROOT/@DEBUG} and U.l_resolve=1 and U.oi_etty = {$DOCROOT/@ETTY} and
I.c_estado_ej=\'R\' and T.c_estado=\'WP\' 

{%?($DOCROOT/@fil-group!='') {% and V.c_var_group={$DOCROOT/@fil-group} %} {% %} %}
{%?($DOCROOT/@fil-cond1 !='' and $DOCROOT/@fil-value1!='') {%=' and '+translate(translate(translate($DOCROOT/@fil-cond1,'[I]','I'),'[W]','W'),'[V]','V') %} {% %} %}
{%?($DOCROOT/@fil-cond2 !='' and $DOCROOT/@fil-value2!='') {%=' and '+translate(translate(translate($DOCROOT/@fil-cond2,'[I]','I'),'[W]','W'),'[V]','V') %} {% %} %}
{%?($DOCROOT/@fil-estado!='') {%=' and '+translate(translate(translate(translate($DOCROOT/@fil-estado,'[I]','I'),'[W]','W'),'[V]','V'),'[T]','T') %}  {% %} %}
{%?($SOURCE/@wf!='') {% and W.c_wf={$SOURCE/@wf} %} {% %} %}
order by
f_vencimiento asc
	')/ROWS/ROW

head.script:
						var SelectedMODE="TASK";
var g_MODE, g_WF, g_UT, g_FIL, g_FIL2, g_FIL3, g_SIZE, g_PAGE, g_INSTANCE, g_LAST, g_DEBUG, g_ETTY, g_TOTAL;

function amp()
{
	return String.fromCharCode(38);
}

function redrawDiv1()
{
	objD=document.getElementById("table_div");
	objD.style.width="500px";
	window.setTimeout("redrawDiv()",100);
}

function redrawDiv()
{
	objD=document.getElementById("table_div");
	objT=document.getElementById("table_td");

	objD.style.width=objT.clientWidth+"px";
}

function SetTableHTML(mode, wf, fil, fil2, fil3, size, page, last, total, instance, innerHTML)
{
	g_MODE    =mode;
	g_WF      =wf;
	g_FIL     =fil; 
	g_FIL2    =fil2; 
	g_FIL3    =fil3; 
	g_SIZE    =size; 
	g_PAGE    =page; 
	g_INSTANCE=instance;
	g_LAST    =last;
	g_TOTAL   =total; 

 	document.getElementById("table_div").innerHTML=innerHTML;

 	document.getElementById("TD_TOTAL").innerHTML=g_TOTAL+" Registros";
 	document.getElementById("TD_PAGE").innerHTML=g_PAGE + " de " +g_LAST;

}

function LoadPage(mode, wf, fil, fil2, fil3, size, page, instance)
{  
	var crc = parent.CRC32("PARAMS:file=NucleusWF.Base.Ejecucion.ConsolaTareas.rpt|size="+size+"|mode="+mode+"|fil="+fil+"|fil2="+fil2+"|fil3="+fil3+"|oi_instance=|debugetty="+g_ETTY+"|debug="+g_DEBUG+"|reload=1");    

	obj=document.getElementById("main");
	objFrame=document.getElementById("loadhidden");
	objFrame.src="ReportViewer.aspx?ut="+g_UT+amp()+"file=NucleusWF.Base.Ejecucion.ConsolaTareas.rpt"+amp()+"size="+size+amp()+"page="+page+amp()+"wf="+wf+amp()+"mode="+mode+amp()+"fil="+fil+amp()+"fil2="+fil2+amp()+"fil3="+fil3+amp()+"oi_instance="+amp()+"debugetty="+g_ETTY+amp()+"debug="+g_DEBUG+amp()+"reload=1"+amp()+"crc="+crc;
	//window.location="ReportViewer.aspx?ut="+g_UT+amp()+"file=NucleusWF.Base.Ejecucion.ConsolaTareas.rpt"+amp()+"size="+size+amp()+"page="+page+amp()+"wf="+wf+amp()+"mode="+mode+amp()+"fil="+fil+amp()+"fil2="+fil2+amp()+"fil3="+fil3+amp()+"oi_instance="+instance+amp()+"debugetty="+g_ETTY+amp()+"debug="+g_DEBUG+amp()+"reload=1";
}

function SelectInstance(oi_instance)
{
	LoadPage(g_MODE, g_WF, g_FIL, g_FIL2, g_FIL3, g_SIZE, g_PAGE, oi_instance);
}         

function RefreshList()
{
	LoadPage(g_MODE, g_WF, g_FIL, g_FIL2, g_FIL3, g_SIZE, g_PAGE, g_INSTANCE);
}         

function FirstPage()
{
	obj=document.getElementById("main");

	if (g_PAGE!="1")
		LoadPage(g_MODE, g_WF, g_FIL, g_FIL2, g_FIL3, g_SIZE, 1, g_INSTANCE);
}

function PrevPage()
{
	if (g_PAGE!="1")
		LoadPage(g_MODE, g_WF, g_FIL, g_FIL2, g_FIL3, g_SIZE, parseInt(g_PAGE,10)-1, g_INSTANCE);


}

function NextPage()
{
	if (g_PAGE!=g_LAST)
		LoadPage(g_MODE, g_WF, g_FIL, g_FIL2, g_FIL3, g_SIZE, parseInt(g_PAGE,10)+1, g_INSTANCE);
}

function LastPage()
{
	if (g_PAGE!=g_LAST)
		LoadPage(g_MODE, g_WF, g_FIL, g_FIL2, g_FIL3, g_SIZE, parseInt(g_LAST,10), g_INSTANCE);
}

function ShowInstance(obj)
{ 
	if (g_INSTANCE!=obj.getAttribute("nmd-instance"))
	{             
		if (g_INSTANCE!="") 
		{                  
			obj2=document.getElementById("TR_"+g_INSTANCE);
			obj2.className="TABLE_REGS_TR";
		}
		obj.className="TABLE_REGS_TR_SELECT";
		g_INSTANCE=obj.getAttribute("nmd-instance");
		parent.ShowInstance(g_INSTANCE, obj.getAttribute("nmd-thread"));
	}
}                    

function OpenInstance(obj)
{                    
	parent.OpenInstance(obj.getAttribute("nmd-instance"), obj.getAttribute("nmd-thread"));
}                    


function TRMouseOut(obj)
{
	if (g_INSTANCE!=obj.getAttribute("nmd-instance"))
		obj.className="TABLE_REGS_TR";
}

function TRMouseOver(obj)
{                       
	if (g_INSTANCE!=obj.getAttribute("nmd-instance"))
		obj.className="TABLE_REGS_TR_OVER";
}

function AutoRefresh() { RefreshList(); window.setTimeout("AutoRefresh();",60000); }

function RefreshTaskList(urlListPage,urlListWF,urlListMode,urlListfil1,urlListfil2,urlListfil3,DebugEtty)
{
	g_MODE    =urlListMode;
	g_WF      =urlListWF;
	g_FIL     =urlListfil1; 
	g_FIL2    =urlListfil2; 
	g_FIL3    =urlListfil3; 
	g_PAGE    =urlListPage; 
	g_ETTY    =DebugEtty; 

	RefreshList();
}

function OnLoadHTML()
{          
	obj=document.getElementById("main");
	g_MODE    =obj.getAttribute("nmd-mode");
	g_WF      =obj.getAttribute("nmd-wf");
	g_UT      =obj.getAttribute("nmd-ut");  
	g_FIL     =obj.getAttribute("nmd-fil"); 
	g_FIL2    =obj.getAttribute("nmd-fil2"); 
	g_FIL3    =obj.getAttribute("nmd-fil3"); 
	g_SIZE    =obj.getAttribute("nmd-size"); 
	g_PAGE    =obj.getAttribute("nmd-page"); 
	g_INSTANCE=obj.getAttribute("nmd-instance");
	g_LAST    =obj.getAttribute("nmd-last"); 
	g_DEBUG   =obj.getAttribute("nmd-debug"); 
	g_ETTY    =obj.getAttribute("nmd-etty"); 
	g_TOTAL   =obj.getAttribute("nmd-total"); 

	if (obj.getAttribute("nmd-reload")=="1")
	{     
		objD=document.getElementById("table_div");
		parent.SetTableHTML(g_MODE, g_WF, g_FIL, g_FIL2, g_FIL3, g_SIZE, g_PAGE, g_LAST, g_TOTAL, g_INSTANCE, objD.innerHTML);
	} else
	{
		window.setTimeout("redrawDiv();",10);
		window.setTimeout("AutoRefresh();",60000);

		parent.SetWindowTask(window);
		parent.SetListPage(parseInt(g_PAGE,10));
	}
}

function resize()
{                 
	redrawDiv1();
}
